#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int **sets = (int **)malloc(N * sizeof(int *));
        for (int i = 0; i < N; i++) {
            int len;
            scanf("%d", &len);
            sets[i] = (int *)malloc(len * sizeof(int));
            for (int j = 0; j < len; j++) {
                scanf("%d", &sets[i][j]);
            }
        }
        int count = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                int *union_set = (int *)malloc(K * sizeof(int));
                int union_len = 0;
                for (int k = 0; k < K; k++) {
                    union_set[k] = 0;
                }
                for (int k = 0; k < len; k++) {
                    union_set[sets[i][k] - 1] = 1;
                }
                for (int k = 0; k < len; k++) {
                    union_set[sets[j][k] - 1] = 1;
                }
                int union_size = 0;
                for (int k = 0; k < K; k++) {
                    if (union_set[k] == 1) {
                        union_size++;
                    }
                }
                if (union_size == K) {
                    count++;
                }
                free(union_set);
            }
        }
        printf("%d\n", count);
        for (int i = 0; i < N; i++) {
            free(sets[i]);
        }
        free(sets);
    }
    return 0;
}

