import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            int K = scanner.nextInt();
            int[][] sets = new int[N][];
            for (int i = 0; i < N; i++) {
                int len = scanner.nextInt();
                sets[i] = new int[len];
                for (int j = 0; j < len; j++) {
                    sets[i][j] = scanner.nextInt();
                }
            }
            int count = 0;
            for (int i = 0; i < N; i++) {
                for (int j = i + 1; j < N; j++) {
                    boolean[] unionSet = new boolean[K];
                    for (int k = 0; k < sets[i].length; k++) {
                        unionSet[sets[i][k] - 1] = true;
                    }
                    for (int k = 0; k < sets[j].length; k++) {
                        unionSet[sets[j][k] - 1] = true;
                    }
                    int unionSize = 0;
                    for (int k = 0; k < K; k++) {
                        if (unionSet[k]) {
                            unionSize++;
                        }
                    }
                    if (unionSize == K) {
                        count++;
                    }
                }
            }
            System.out.println(count);
        }
    }
}

