const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;

function nextInt() {
    return parseInt(lines[idx++]);
}

function nextInts() {
    return lines[idx++].trim().split(' ').map(Number);
}

let T = nextInt();
while (T-- > 0) {
    let [N, K] = nextInts();
    let sets = [];
    for (let i = 0; i < N; i++) {
        let len_i = nextInt();
        let set_i = nextInts();
        sets.push(set_i);
    }
    let count = 0;
    for (let i = 0; i < N; i++) {
        for (let j = i + 1; j < N; j++) {
            let unionSet = new Set([...sets[i], ...sets[j]]);
            if (unionSet.size == K) {
                count++;
            }
        }
    }
    console.log(count);
}
